cd /tmp/symbols

# Get proper resolution - find the closest symbol that contains each address
# Using a proper approach: for each address, find the symbol where addr >= sym_start && addr < sym_start + sym_size
python3 << 'PYEOF'
import subprocess, re

# Parse symbols
syms = []
result = subprocess.run(['readelf', '--dyn-syms', 'libmonosgen-2.0.so'], capture_output=True, text=True)
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 8 and parts[3] == 'FUNC':
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            name = parts[7]
            if addr > 0:
                syms.append((addr, size, name))
        except ValueError:
            pass

syms.sort(key=lambda x: x[0])

targets = {
    '#01': 0x222098,
    '#02': 0x222234,
    '#03': 0x19bac0,
    '#06': 0x19bc14,
}

for frame, target in targets.items():
    best = None
    for addr, size, name in syms:
        if addr <= target:
            best = (addr, size, name)
        else:
            break
    if best:
        offset = target - best[0]
        print(f"  {frame} pc 0x{target:x} -> {best[2]}+0x{offset:x} (size={best[1]})")
    else:
        print(f"  {frame} pc 0x{target:x} -> ???")
