cd /tmp/symbols

# Get full symbol names using nm or objdump
python3 << 'PYEOF'
import subprocess

# Use objdump for full symbol names
result = subprocess.run(['objdump', '-T', 'libmonosgen-2.0.so'], capture_output=True, text=True)
syms = []
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 2 and 'F' in parts and '.text' in line:
        try:
            addr = int(parts[0], 16)
            # Find the function name (last element)
            name = parts[-1]
            syms.append((addr, name))
        except ValueError:
            pass

# Also try readelf -W for wide output
result2 = subprocess.run(['readelf', '-W', '--dyn-syms', 'libmonosgen-2.0.so'], capture_output=True, text=True)
syms2 = []
for line in result2.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 8 and parts[3] == 'FUNC':
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            name = parts[7]
            if addr > 0:
                syms2.append((addr, size, name))
        except ValueError:
            pass

syms2.sort(key=lambda x: x[0])

targets = {
    '#01': 0x222098,
    '#02': 0x222234,
    '#03': 0x19bac0,
    '#06': 0x19bc14,
}

for frame, target in targets.items():
    best = None
    for addr, size, name in syms2:
        if addr <= target:
            best = (addr, size, name)
        else:
            break
    if best:
        offset = target - best[0]
        in_bounds = "✓" if offset < best[1] else f"(past end by {offset-best[1]})"
        print(f"  {frame} pc 0x{target:x} -> {best[2]}+0x{offset:x} {in_bounds}")

# Show all symbols near 0x222098
print("\n--- Symbols near 0x222000-0x223000 ---")
for addr, size, name in syms2:
    if 0x21f000 <= addr <= 0x224000:
        print(f"  0x{addr:x} size={size} {name}")

print("\n--- Symbols near 0x19b000-0x19c000 ---")
for addr, size, name in syms2:
    if 0x199000 <= addr <= 0x19d000:
        print(f"  0x{addr:x} size={size} {name}")
